module top_module(A, B, add, clk, sum);input [31:0] A;
   input [31:0] B;
   input add;
   input clk;

   output [31:0] sum;

   wire [31:0] result;

   reg [31:0] sum_reg;

     wire _n01 = A[0] ^ B[0];
  wire _c01 = A[0] & B[0];
  wire _n02 = A[1] ^ B[1] ^ _c01;
  wire _c02 = (A[1] & B[1]) | (A[1] & _c01) | (B[1] & _c01);
  wire _n03 = A[2] ^ B[2] ^ _c02;
  wire _c03 = (A[2] & B[2]) | (A[2] & _c02) | (B[2] & _c02);
  wire _n04 = A[3] ^ B[3] ^ _c03;
  wire _c04 = (A[3] & B[3]) | (A[3] & _c03) | (B[3] & _c03);
  assign result = {_n01, _n02, _n03, _n04};

   always @ (posedge clk)
     if (add) sum_reg <= result;

   assign sum = add ? result : sum_reg;
endmodule
